#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    vec2 d = uTexSize.zw*4;
    vec3 dx = GetBlur1(fract(vUv+vec2(1,0)*d))-GetBlur1(fract(vUv-vec2(1,0)*d));
    vec3 dy = GetBlur1(fract(vUv+vec2(0,1)*d))-GetBlur1(fract(vUv-vec2(0,1)*d));
    vec3 b1 = GetBlur1(vUv) - 0;
    d *= -1;
    float d2 = d*4;
    float1 c1 = 0.042;
    float1 c2 = -0.0075;


    vec2 my_uv = vUv - vec2(dx.y,dy.y)*d - vec2(dx.x,dy.x)*d2;
    ret.y = texture( sampler_fc_main, my_uv-floor(my_uv)).y;
    ret.y += (ret.y - b1.y)*c1 + c2;


    my_uv = vUv - vec2(dx.x,dy.x)*d - vec2(dx.z,dy.z)*d2;
    ret.x = texture( sampler_fc_main, my_uv-floor(my_uv)).x;
    ret.x += (ret.x - b1.x)*c1 + c2;


    my_uv = vUv - vec2(dx.z,dy.z)*d - vec2(dx.y,dy.y)*d2;
    ret.z = texture( sampler_fc_main, my_uv-floor(my_uv)).z;
    ret.z += (ret.z - b1.z)*c1 + c2;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((my_uv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(0.6,1.6,0.3)*0.05 +
                      uTime*vec3(1.3,1.4,1.4)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float iter = 4+10*clamp01(uTexSize.x/1024*vUv.y);
ret = Get1(vUv); ret1 = ret; ret2 = ret;
for (int n =1; n < 10; n++) {
  ret1 = max(ret1,Get1(vUv+uTexSize.zw*vec2(n,0)));
//  ret2 = max(ret2,Get1(vUv+uTexSize.zw*vec2(0,n)));
}
struc = ret1;
mask = clamp01(1-16*lum(struc));
struc *= .06/(length(vRadius/2-length((ret1+ret2*0.2))+0.6));

//BACK
//uv4 = (vUv-0.5) * (1+0*exp(-pow((vUv.x-0.5)*3-2*q14,2)))+0.5;


noise = (texture(sampler_noise_lq,2*uv4).r+0.25);
noise *= 1-texture(sampler_noise_lq,2*uv4+uTexSize.zw*-4).r;
// (MWmod) noise *= (0.5+ 0.5*(lum(texture(sampler_rand00,vUv)) > 0.5))*2;
ret = 0.05+noise*0.5*(1-vRadius);  // texLum (orig *0.5)

ret *= clamp01(1-lum(GetBlur2(uv4-0.13))*8);
ret = mix(ret,struc, !mask);

//NEW FLASH
for (int n = 1; n <= 3; n++)
{
  uvt = texture(sampler_noise_lq,n*0.074+q25).xy;
  uv3 = uv4-uvt;
  uv3 = multiply(uv3,mat2 (q23,q24,-q24,q23));
  cross = (0.0001+abs(uv3.x+uv3.y) *abs(uv3.x-uv3.y)) * length(uv3);
  flash2 = (3*q22/cross) *GetBlur1(uvt) * (uvt.x < 0.9)* (uvt.x > 0.1)* (uvt.y < 0.9)* (uvt.y > 0.1);
  flash2 += 100000*mask*q22*clamp01(1-2*length(uv3-0.1)) *noise*GetBlur1(uvt);
  ret += flash2;
}
//ret = GetPixel(vUv);
//ret *= 1.4;  // gamma  (orig 1.4  und  deakt)
//ret /= vec3(1.8,-0.8,2.8);
ret /= vec3(0.6,2.6,-0.6);
ret /= vec3(1.5,1.8,-2.0);
ret /= vec3(2.0,-0.2,-2.3);
ret /= vec3(1.0,-1.5,-0.1);
ret /= vec3(0.7,0.6,1.1);

  fragColor = ret;
}
